import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Product, SalesOrder, SalesOrderLine } from '../../core/models';

/**
 * Sales order detail: line-item editor (draft only) + status transitions
 * (Confirm → confirmed, Fulfill → fulfilled decrementing stock / 400 when
 * insufficient, Generate invoice → invoiced). service_agent wires
 * getSalesOrder / update / confirmSO / fulfillSO / invoiceSO and surfaces the
 * 400 insufficient-stock error.
 */
@Component({
  selector: 'app-sales-order-detail',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './sales-order-detail.component.html',
  styleUrl: './sales-order-detail.component.css',
})
export class SalesOrderDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly working = signal(false);
  readonly createdInvoiceId = signal<string | null>(null);
  id = '';

  readonly products = signal<Product[]>([
    { id: 'p1', sku: 'WID-001', name: 'Widget', costCents: 450, priceCents: 999, onHand: 120 },
    { id: 'p2', sku: 'GAD-002', name: 'Gadget', costCents: 1200, priceCents: 2499, onHand: 64 },
    { id: 'p3', sku: 'SPR-003', name: 'Sprocket', costCents: 80, priceCents: 249, onHand: 5 },
  ]);

  readonly order = signal<SalesOrder>({
    id: 'so1',
    customerId: 'c1',
    status: 'draft',
    customer: { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example' },
    lines: [
      { id: 'l1', soId: 'so1', productId: 'p1', qty: 50, unitPriceCents: 999,
        product: { id: 'p1', sku: 'WID-001', name: 'Widget', costCents: 450, priceCents: 999, onHand: 120 } },
    ],
  });

  readonly canEdit = computed(() => this.auth.isSales());
  readonly isDraft = computed(() => this.order().status === 'draft');
  readonly totalCents = computed(() =>
    (this.order().lines ?? []).reduce((sum, l) => sum + l.qty * l.unitPriceCents, 0),
  );

  newLine = { productId: '', qty: '1' };

  constructor(public auth: AuthService, private route: ActivatedRoute, private router: Router) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    this.newLine.productId = this.products()[0]?.id ?? '';
    // service_agent: this.order.set(await ApiService.getSalesOrder(this.id)).
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  onHandFor(productId: string): number {
    return this.products().find((p) => p.id === productId)?.onHand ?? 0;
  }

  addLine(): void {
    const p = this.products().find((x) => x.id === this.newLine.productId);
    if (!p) return;
    const qty = Math.max(1, parseInt(this.newLine.qty || '1', 10));
    const line: SalesOrderLine = {
      id: 'l' + Date.now(),
      soId: this.order().id,
      productId: p.id,
      qty,
      unitPriceCents: p.priceCents,
      product: p,
    };
    this.order.update((o) => ({ ...o, lines: [...(o.lines ?? []), line] }));
    this.newLine.qty = '1';
  }

  removeLine(lineId: string): void {
    this.order.update((o) => ({ ...o, lines: (o.lines ?? []).filter((l) => l.id !== lineId) }));
  }

  confirm(): void {
    this.working.set(true);
    // service_agent: ApiService.confirmSO(this.id).
    this.order.update((o) => ({ ...o, status: 'confirmed' }));
    this.working.set(false);
  }

  fulfill(): void {
    this.error.set(null);
    // Demonstrate the 400 insufficient-stock path from the backend.
    const short = (this.order().lines ?? []).find((l) => l.qty > this.onHandFor(l.productId));
    if (short) {
      this.error.set(
        `Insufficient stock for ${short.product?.name || short.productId}: need ${short.qty}, only ${this.onHandFor(short.productId)} on hand.`,
      );
      return;
    }
    this.working.set(true);
    // service_agent: ApiService.fulfillSO(this.id) — surfaces 400 into this.error.
    this.order.update((o) => ({ ...o, status: 'fulfilled' }));
    this.working.set(false);
  }

  generateInvoice(): void {
    this.working.set(true);
    // service_agent: ApiService.invoiceSO(this.id) then navigate to the invoice.
    const invId = 'inv-' + this.order().id;
    this.order.update((o) => ({ ...o, status: 'invoiced' }));
    this.createdInvoiceId.set(invId);
    this.working.set(false);
  }
}
